<?php
namespace Tests\Feature;
use App\Domain\Wallet\Data\GoldTransactionEntry;use App\Domain\Wallet\Exceptions\IdempotencyConflictException;use App\Domain\Wallet\Exceptions\InsufficientGoldException;use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Models\Character;use App\Models\GoldTransaction;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use InvalidArgumentException;use Tests\TestCase;
class WalletServiceTest extends TestCase {use RefreshDatabase;private $c;private $s;protected function setUp():void{parent::setUp();$this->c=Character::factory()->for(User::factory())->create();$this->s=app(WalletService::class);}public function test_wallet_operations_and_entries(){$this->assertSame(0,$this->s->balance($this->c)->balance());$this->s->credit($this->c,100,GoldReasonCode::ADMIN_GRANT,'grant');$this->s->credit($this->c,50,GoldReasonCode::CORRECTION);$d=$this->s->debit($this->c,150,GoldReasonCode::ADMIN_REMOVE);$this->assertSame(0,$d->balanceAfter());$this->assertContainsOnlyInstancesOf(GoldTransactionEntry::class,$this->s->transactions($this->c));$this->assertSame(3,GoldTransaction::count());}public function test_invalid_operations_rollback(){foreach([0,-1] as $a){try{$this->s->credit($this->c,$a,GoldReasonCode::ADMIN_GRANT);}catch(InvalidArgumentException $e){}}$this->s->credit($this->c,10,GoldReasonCode::ADMIN_GRANT);try{$this->s->debit($this->c,11,GoldReasonCode::ADMIN_REMOVE);}catch(InsufficientGoldException $e){}$this->assertSame(10,$this->s->balance($this->c)->balance());$this->assertSame(1,GoldTransaction::count());}public function test_idempotency_and_conflicts(){$a=$this->s->credit($this->c,20,GoldReasonCode::ADMIN_GRANT,'x','job',1,'key');$b=$this->s->credit($this->c,20,GoldReasonCode::ADMIN_GRANT,'x','job',1,'key');$this->assertSame($a->transactionId(),$b->transactionId());foreach(['',str_repeat('x',192)] as $key){try{$this->s->credit($this->c,1,GoldReasonCode::ADMIN_GRANT,null,null,null,$key);$this->fail();}catch(InvalidArgumentException $e){}}$this->expectException(IdempotencyConflictException::class);$this->s->credit($this->c,20,GoldReasonCode::ADMIN_GRANT,'different','job',1,'key');}public function test_overflow_is_rejected_without_changes(){DB::table('character_wallets')->insert(['character_id'=>$this->c->id,'gold_balance'=>PHP_INT_MAX,'created_at'=>now(),'updated_at'=>now()]);try{$this->s->credit($this->c,1,GoldReasonCode::ADMIN_GRANT);$this->fail();}catch(InvalidArgumentException $e){}$this->assertSame(PHP_INT_MAX,$this->s->balance($this->c)->balance());$this->assertSame(0,GoldTransaction::count());}}
